import React, { useState, useEffect, useRef, useCallback } from 'react';
import { Outlet, useNavigate, useLocation } from 'react-router-dom';
import { Menu, X, ChevronDown, LayoutDashboard, FileText, ClipboardList, Users, Box, Bath, Calendar, Calculator, BarChart3, Settings, Globe, Send, Wrench, UserCheck, Clock, Truck } from 'lucide-react';

const accordionGroups = [
  {
    key: 'dashboard',
    label: 'INICIO',
    icon: LayoutDashboard,
    path: '/',
    end: true,
    subItems: null,
  },
  {
    key: 'presupuestos',
    label: 'PRESUPUESTOS',
    icon: FileText,
    subItems: [
      { label: 'Presupuesto Local', path: '/presupuestos', icon: FileText },
      { label: 'Presupuesto En Línea', path: '/presupuestos-online', icon: Globe },
      { label: 'Presupuestos Realizados', path: '/presupuestos?estado=CONVERTIDO+A+OT', icon: Clock },
    ],
  },
  {
    key: 'ordenes',
    label: 'ÓRDENES DE TRABAJO',
    icon: ClipboardList,
    subItems: [
      { label: 'Nueva Orden', path: '/ordenes/nuevo', icon: Send },
      { label: 'Órdenes Activas', path: '/ordenes', icon: ClipboardList },
      { label: 'En Taller', path: '/ordenes?estado=EN+EL+TALLER', icon: Wrench },
      { label: 'Entregadas', path: '/ordenes?estado=ENTREGADO', icon: Truck },
    ],
  },
  {
    key: 'herramientas',
    label: 'HERRAMIENTAS / STOCK',
    icon: Box,
    subItems: [
      { label: 'Stock de Piletas', path: '/stock-piletas', icon: Bath },
      { label: 'Materiales', path: '/materiales', icon: Box },
      { label: 'Calculadora', path: '/calculadora', icon: Calculator },
    ],
  },
  {
    key: 'agenda',
    label: 'AGENDA',
    icon: Calendar,
    subItems: [
      { label: 'Clientes', path: '/clientes', icon: Users },
      { label: 'Mediciones', path: '/mediciones', icon: Calendar },
    ],
  },
  {
    key: 'reportes',
    label: 'REPORTES',
    icon: BarChart3,
    path: '/reportes',
    subItems: null,
  },
  {
    key: 'config',
    label: 'CONFIGURACIÓN',
    icon: Settings,
    path: '/configuracion',
    subItems: null,
  },
];

export default function Layout() {
  const [isOpen, setIsOpen] = useState(false);
  const [isPinned, setIsPinned] = useState(() => localStorage.getItem('sidebarPinned') === 'true');
  const [mobileOpen, setMobileOpen] = useState(false);
  const [expanded, setExpanded] = useState('');
  const leaveTimer = useRef(null);
  const sidebarRef = useRef(null);
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    localStorage.setItem('sidebarPinned', isPinned);
  }, [isPinned]);

  useEffect(() => {
    const handleMouseMove = (e) => {
      if (isPinned) return;
      if (e.clientX <= 15) {
        if (leaveTimer.current) {
          clearTimeout(leaveTimer.current);
          leaveTimer.current = null;
        }
        setIsOpen(true);
      }
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, [isPinned]);

  const handleMouseLeave = useCallback(() => {
    if (isPinned) return;
    if (leaveTimer.current) clearTimeout(leaveTimer.current);
    leaveTimer.current = setTimeout(() => {
      setIsOpen(false);
    }, 500);
  }, [isPinned]);

  const handleMouseEnter = useCallback(() => {
    if (isPinned) return;
    if (leaveTimer.current) {
      clearTimeout(leaveTimer.current);
      leaveTimer.current = null;
    }
    setIsOpen(true);
  }, [isPinned]);

  const togglePin = () => setIsPinned((p) => !p);

  const sidebarVisible = isPinned || isOpen || mobileOpen;

  const isGroupActive = (group) => {
    if (group.path) return location.pathname === group.path;
    if (group.subItems) return group.subItems.some((s) => location.pathname.startsWith(s.path.split('?')[0]));
    return false;
  };

  const toggleExpand = (key) => {
    setExpanded((prev) => (prev === key ? '' : key));
  };

  const handleNavigate = (path) => {
    navigate(path);
    setMobileOpen(false);
    if (!isPinned) setIsOpen(false);
  };

  return (
    <div>
      {/* Trigger edge */}
      <div
        className={`sidebar-trigger${isPinned ? ' hidden' : ''}`}
        onMouseEnter={handleMouseEnter}
      />

      {/* Mobile hamburger */}
      <button
        className="btn btn-outline mobile-hamburger"
        onClick={() => setMobileOpen(!mobileOpen)}
        style={{ position: 'fixed', top: 12, left: 12, zIndex: 1100 }}
      >
        {mobileOpen ? <X size={18} /> : <Menu size={18} />}
      </button>

      <aside
        ref={sidebarRef}
        className={`sidebar accordion${sidebarVisible ? ' visible' : ''}${isPinned ? ' pinned' : ''}`}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
      >
        {/* Pin button */}
        <button onClick={togglePin} title={isPinned ? 'Desfijar' : 'Fijar'} className="pin-btn">
          {isPinned ? '📌' : '📍'}
        </button>

        {/* Red header */}
        <div className="menu-header">
          <span>MENÚ</span>
          <Menu size={18} />
        </div>

        <ul className="menu-links">
          {accordionGroups.map((group) => (
            <li key={group.key} className={`menu-item${isGroupActive(group) ? ' active' : ''}`}>
              {group.subItems ? (
                <>
                  <button className="menu-btn" onClick={() => toggleExpand(group.key)}>
                    <span><group.icon size={18} className="icon-main" style={{ marginRight: 10 }} />{group.label}</span>
                    <ChevronDown size={14} className={`arrow${expanded === group.key ? ' rotated' : ''}`} />
                  </button>
                  <ul className="submenu" style={{ maxHeight: expanded === group.key ? (group.subItems.length * 44) + 'px' : 0 }}>
                    {group.subItems.map((sub) => (
                      <li key={sub.path} className={location.pathname.startsWith(sub.path.split('?')[0]) && !location.search ? 'sub-active' : ''}>
                        <a href="#!" onClick={(e) => { e.preventDefault(); handleNavigate(sub.path); }}>
                          <sub.icon size={15} style={{ marginRight: 8, opacity: 0.7 }} />
                          {sub.label}
                        </a>
                      </li>
                    ))}
                  </ul>
                </>
              ) : (
                <button className="menu-btn" onClick={() => handleNavigate(group.path)}>
                  <span><group.icon size={18} className="icon-main" style={{ marginRight: 10 }} />{group.label}</span>
                </button>
              )}
            </li>
          ))}
        </ul>
      </aside>

      {/* Mobile overlay */}
      {mobileOpen && (
        <div onClick={() => setMobileOpen(false)} className="mobile-overlay" />
      )}

      <div className="main-content">
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 24 }}>
          <div />
          <div style={{ fontSize: 14, color: '#64748b' }}>
            {new Date().toLocaleDateString('es-AR', {
              weekday: 'long',
              year: 'numeric',
              month: 'long',
              day: 'numeric',
            })}
          </div>
        </div>
        <Outlet />
      </div>
    </div>
  );
}
